// ─────────────────────────────────────────────────────────────────────────────
// PUBLICAR VEHÍCULO EN INSTAGRAM
// ─────────────────────────────────────────────────────────────────────────────
// Variables requeridas en n8n → Workflow Settings → Variables:
//   IG_USER_ID     : ID del perfil de Instagram Business (ej: 17841234567890)
//   IG_ACCESS_TOKEN: Token de larga duración de Meta Graph API
// ─────────────────────────────────────────────────────────────────────────────

const IG_USER_ID = $vars.IG_USER_ID;
const IG_ACCESS_TOKEN = $vars.IG_ACCESS_TOKEN;
const BASE_URL = 'https://graph.facebook.com/v21.0';

if (!IG_USER_ID || !IG_ACCESS_TOKEN) {
  throw new Error('Faltan variables del workflow. Configurá IG_USER_ID e IG_ACCESS_TOKEN en Workflow Settings → Variables.');
}

const items = $input.all();
const raw = items[0].json;
const data = raw.body || raw;
const vehicle = data.vehicle;

if (!vehicle) {
  throw new Error('Payload inválido: falta el objeto vehicle.');
}

// ── Construir caption ────────────────────────────────────────────────────────
const titulo = vehicle.brand + ' ' + vehicle.model + ' ' + vehicle.year + (vehicle.version ? ' ' + vehicle.version : '');
const km = vehicle.kilometers > 0
  ? vehicle.kilometers.toLocaleString('es-AR') + ' km'
  : '0 km';
const precio = (vehicle.showPrice !== false && vehicle.price && vehicle.price > 0)
  ? vehicle.currency + ' ' + vehicle.price.toLocaleString('es-AR')
  : '';
const featuresList = (vehicle.features && vehicle.features.length > 0)
  ? vehicle.features.slice(0, 5).join(' • ')
  : '';

let caption = '🚗 ' + titulo + '\n\n' + (vehicle.description || '');
if (featuresList) caption += '\n\n✨ ' + featuresList;
caption += '\n\n📍 ' + km;
if (precio) caption += '\n💰 ' + precio;
caption += '\n\n📲 Consultanos por DM o WhatsApp';

// ── Validar fotos ───────────────────────────────────────────────────────────
// Instagram requiere URLs públicas. Para fotos en Firebase Storage
// asegurate que sean URLs de descarga públicas (no firmadas con expiración corta).
const photos = (vehicle.photos || [])
  .filter(function(p) { return typeof p === 'string' && p.startsWith('http'); })
  .slice(0, 10); // Instagram soporta máximo 10 imágenes en carrusel

if (photos.length === 0) {
  throw new Error('No hay fotos públicas (URLs http/https) disponibles para publicar en Instagram.');
}

try {
  let creation_id;

  if (photos.length === 1) {
    // ── Post imagen única ──────────────────────────────────────────────────
    const containerRes = await this.helpers.httpRequest({
      method: 'POST',
      url: BASE_URL + '/' + IG_USER_ID + '/media',
      qs: {
        image_url: photos[0],
        caption: caption,
        access_token: IG_ACCESS_TOKEN
      }
    });

    if (!containerRes.id) {
      throw new Error('Error al crear contenedor de media: ' + JSON.stringify(containerRes));
    }
    creation_id = containerRes.id;

  } else {
    // ── Post carrusel (2–10 fotos) ─────────────────────────────────────────
    const childIds = [];

    for (var i = 0; i < photos.length; i++) {
      const childRes = await this.helpers.httpRequest({
        method: 'POST',
        url: BASE_URL + '/' + IG_USER_ID + '/media',
        qs: {
          image_url: photos[i],
          is_carousel_item: 'true',
          access_token: IG_ACCESS_TOKEN
        }
      });

      if (!childRes.id) {
        throw new Error('Error al crear item del carrusel (foto ' + (i + 1) + '): ' + JSON.stringify(childRes));
      }
      childIds.push(childRes.id);
    }

    const carouselRes = await this.helpers.httpRequest({
      method: 'POST',
      url: BASE_URL + '/' + IG_USER_ID + '/media',
      qs: {
        media_type: 'CAROUSEL',
        children: childIds.join(','),
        caption: caption,
        access_token: IG_ACCESS_TOKEN
      }
    });

    if (!carouselRes.id) {
      throw new Error('Error al crear contenedor del carrusel: ' + JSON.stringify(carouselRes));
    }
    creation_id = carouselRes.id;
  }

  // ── Esperar que Instagram procese el container (recomendado por Meta) ────
  await new Promise(function(resolve) { setTimeout(resolve, 15000); });

  // ── Publicar el contenedor ───────────────────────────────────────────────
  const publishRes = await this.helpers.httpRequest({
    method: 'POST',
    url: BASE_URL + '/' + IG_USER_ID + '/media_publish',
    qs: {
      creation_id: creation_id,
      access_token: IG_ACCESS_TOKEN
    }
  });

  if (!publishRes.id) {
    throw new Error('Error al publicar el contenedor: ' + JSON.stringify(publishRes));
  }

  return [{
    json: {
      success: true,
      externalId: publishRes.id,
      vehicleId: vehicle.id,
      platform: 'instagram',
      action: 'published',
      message: 'Publicación creada exitosamente en Instagram',
      publishedAt: new Date().toISOString(),
      photoCount: photos.length,
      postType: photos.length === 1 ? 'single' : 'carousel'
    }
  }];

} catch (error) {
  return [{
    json: {
      success: false,
      error: error.message,
      vehicleId: vehicle ? vehicle.id : null,
      platform: 'instagram',
      action: 'publish'
    }
  }];
}

// ─────────────────────────────────────────────────────────────────────────────
// PAUSAR / ARCHIVAR PUBLICACIÓN EN INSTAGRAM
// ─────────────────────────────────────────────────────────────────────────────
// NOTA: Instagram Graph API no soporta una pausa nativa para posts de feed.
// Esta acción intenta archivar el post usando is_hidden=true.
// Si falla (cuentas que no soportan esta operación), el sistema devuelve
// success: true con una nota de que debe pausarse manualmente desde la app.
// El estado 'paused' se sigue guardando en el sistema local de StockAutos.
// ─────────────────────────────────────────────────────────────────────────────

const IG_ACCESS_TOKEN = $vars.IG_ACCESS_TOKEN;
const BASE_URL = 'https://graph.facebook.com/v21.0';

const items = $input.all();
const raw = items[0].json;
const data = raw.body || raw;
const externalId = data.externalId;

if (!externalId) {
  throw new Error('externalId es requerido para pausar la publicación.');
}

if (!IG_ACCESS_TOKEN) {
  throw new Error('Falta la variable IG_ACCESS_TOKEN en Variables del workflow.');
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: BASE_URL + '/' + externalId,
    headers: { 'Content-Type': 'application/json' },
    body: {
      access_token: IG_ACCESS_TOKEN,
      is_hidden: true
    }
  });

  const apiSuccess = response && (response.success === true || response.id);

  return [{
    json: {
      success: true,
      externalId: externalId,
      platform: 'instagram',
      action: 'paused',
      apiHidden: apiSuccess,
      message: apiSuccess
        ? 'Publicación archivada/pausada en Instagram.'
        : 'El estado fue guardado como pausado en StockAutos. Pausar manualmente en Instagram si es necesario.',
      pausedAt: new Date().toISOString(),
      note: 'Para volver a publicar usa la acción delete_republish.'
    }
  }];

} catch (error) {
  // La pausa falla silenciosamente: StockAutos guarda el estado 'paused' igual.
  return [{
    json: {
      success: true,
      externalId: externalId,
      platform: 'instagram',
      action: 'paused',
      apiHidden: false,
      message: 'Estado pausado guardado en StockAutos. No se pudo archivar vía API (' + error.message + ').',
      pausedAt: new Date().toISOString(),
      note: 'Instagram Business puede no soportar is_hidden para este tipo de contenido. Pausar manualmente si es necesario.'
    }
  }];
}

// Recupera el payload original del webhook para usarlo en la republicación.
// El nodo HTTP de eliminación reemplaza el item, así que recuperamos los datos
// del webhook via $('Webhook: Recibir Acción').
const webhookData = $('Webhook: Recibir Acción').first().json;
return [{ json: webhookData.body || webhookData }];

